package com.ichi2.libanki

import org.junit.jupiter.api.Test
import kotlin.test.assertEquals

/**
 * Tests for the fix of images with '#' in filenames.
 * See: https://github.com/ankidroid/Anki-Android/issues/[bug issue number]
 * 
 * Anki stores filenames without encoding on disk (legacy reasons), but needs to 
 * encode them before they're shown in the editor/viewer.
 */
@Suppress("HtmlUnknownTarget", "HtmlRequiredAltAttribute")
class TemplateManagerHashCharTest {

    @Test
    fun `parseSourcesToFileScheme - filename with hash character is properly encoded`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("<img src=\"image#1.png\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/image%231.png">""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - filename with multiple hash characters is properly encoded`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("<img src=\"a#b#c.png\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/a%23b%23c.png">""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - filename with hash and percent is properly encoded`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("<img src=\"file#100%.png\">", mediaDir)
        assertEquals("""<img src="file:///$mediaDir/file%23100%25.png">""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - video with hash character is properly encoded`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("""<video src="video#1.mp4"></video>""", mediaDir)
        assertEquals("""<video src="file:///$mediaDir/video%231.mp4"></video>""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - audio with hash character is properly encoded`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseSourcesToFileScheme("""<audio src="audio#1.mp3"></audio>""", mediaDir)
        assertEquals("""<audio src="file:///$mediaDir/audio%231.mp3"></audio>""", result)
    }

    @Test
    fun `parseSourcesToFileScheme - data URI is not processed`() {
        val result = parseSourcesToFileScheme("""<img src="data:image/png;base64,iVBORw0KGgo=">""", "any_directory")
        assertEquals("""<img src="data:image/png;base64,iVBORw0KGgo=">""", result)
    }

    @Test
    fun `parseVideos - video filename with hash is properly encoded`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"
        val result = parseVideos("[sound:video#1.mp4]", mediaDir)
        assertEquals("""<video src="file:///$mediaDir/video%231.mp4" controls controlsList="nodownload"></video>""", result)
    }
}
"}

